__global__ void kernel_gpu_2(
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    long *lastKnode,
    long *offset_2,
    int *start,
    int *end,
    int *recstart,
    int *reclength,
    int threadsPerBlock)
{
    int bid = blockIdx.x;
    int thid = threadIdx.x;

    if (bid >= count) return;

    long current_knode = currKnode[bid];
    long current_offset = offset[bid];
    long last_knode = lastKnode[bid];
    long last_offset = offset_2[bid];
    int start_val = start[bid];
    int end_val = end[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((knodes[current_knode].keys[thid] <= start_val) && (knodes[current_knode].keys[thid+1] > start_val)) {
                if (knodes[current_offset].indices[thid] < knodes_elem) {
                    current_offset = knodes[current_offset].indices[thid];
                }
            }
            if ((knodes[last_knode].keys[thid] <= end_val) && (knodes[last_knode].keys[thid+1] > end_val)) {
                if (knodes[last_offset].indices[thid] < knodes_elem) {
                    last_offset = knodes[last_offset].indices[thid];
                }
            }
        }
        if (thid == 0) {
            currKnode[bid] = current_offset;
            lastKnode[bid] = last_offset;
            current_knode = current_offset;
            last_knode = last_offset;
        }
    }

    if (thid < threadsPerBlock) {
        if (knodes[current_knode].keys[thid] == start_val) {
            recstart[bid] = knodes[current_knode].indices[thid];
        }
        if (knodes[last_knode].keys[thid] == end_val) {
            reclength[bid] = knodes[last_knode].indices[thid] - recstart[bid] + 1;
        }
    }
}

