#include <cuda.h>
#include <stdlib.h>
#include <stdio.h>

#include "../common.h"

#include "../util/timer/timer.h"

#include "../util/cuda_helper.h"

__global__ void kernel_gpu(
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    int bid = blockIdx.x;
    int thid = threadIdx.x;

    if (bid >= count) return;

    long local_currKnode = currKnode[bid];
    long local_offset = offset[bid];
    int key_val = keys[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < order) {
            if ((knodes[local_currKnode].keys[thid] <= key_val) && (knodes[local_currKnode].keys[thid+1] > key_val)) {
                if (knodes[local_offset].indices[thid] < knodes_elem) {
                    local_offset = knodes[local_offset].indices[thid];
                }
            }
        }
        if (thid == 0) {
            local_currKnode = local_offset;
        }
    }

    if (thid < order) {
        if (knodes[local_currKnode].keys[thid] == key_val) {
            ans[bid].value = records[knodes[local_currKnode].indices[thid]].value;
        }
    }

    if (thid == 0) {
        currKnode[bid] = local_currKnode;
        offset[bid] = local_offset;
    }
}

void 
kernel_cpu(	int cores_arg,
			record *records,
			knode *knodes,
			long knodes_elem,
			int order,
			long maxheight,
			int count,
			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
    long long time0;
    long long time1;
    long long time2;

    time0 = get_time();

    setdevice();

    int threadsPerBlock;
    threadsPerBlock = order < 1024 ? order : 1024;

    time1 = get_time();

    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaMalloc(&d_records, count * sizeof(record));
    cudaMalloc(&d_knodes, knodes_elem * sizeof(knode));
    cudaMalloc(&d_currKnode, count * sizeof(long));
    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMalloc(&d_keys, count * sizeof(int));
    cudaMalloc(&d_ans, count * sizeof(record));

    cudaMemcpy(d_records, records, count * sizeof(record), cudaMemcpyHostToDevice);
    cudaMemcpy(d_knodes, knodes, knodes_elem * sizeof(knode), cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_keys, keys, count * sizeof(int), cudaMemcpyHostToDevice);
    cudaMemcpy(d_ans, ans, count * sizeof(record), cudaMemcpyHostToDevice);

    time2 = get_time();

    kernel_gpu<<<count, threadsPerBlock>>>(
        d_records,
        d_knodes,
        knodes_elem,
        order,
        maxheight,
        count,
        d_currKnode,
        d_offset,
        d_keys,
        d_ans);

    checkCUDAError("kernel launch");
    cudaDeviceSynchronize();

    cudaMemcpy(ans, d_ans, count * sizeof(record), cudaMemcpyDeviceToHost);
    cudaMemcpy(currKnode, d_currKnode, count * sizeof(long), cudaMemcpyDeviceToHost);
    cudaMemcpy(offset, d_offset, count * sizeof(long), cudaMemcpyDeviceToHost);

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);

    long long time3 = get_time();

    printf("Time spent in different stages of GPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : GPU: SET DEVICE\n",					(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time3-time0) * 100);
    printf("%15.12f s, %15.12f % : GPU: KERNEL\n",					(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time3-time0) * 100);
    printf("%15.12f s, %15.12f % : GPU: COPY BACK\n",					(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time3-time0) * 100);

    printf("Total time:\n");
    printf("%.12f s\n", 												(float) (time3-time0) / 1000000);
}

