	while (true) {
		for (i = 0; i < c->num_keys; i++) {
			if (verbose_output)

			printf("%d ", c->keys[i]);
		}
		if (verbose_output)

		if (c->pointers[order - 1] != NULL) {
			printf(" | ");
			c = (node *) c->pointers[order - 1];
		}
		else
		break;
	}
	printf("\n");
}

