int 
path_to_root( node* root, node* child ) 
{
	int length = 0;
	node * c = child;
	while (c != root) {
		c = c->parent;
		length++;
	}
	return length;
}

void 
print_tree( node* root ) 
{

	node * n = NULL;
	int i = 0;
	int rank = 0;
	int new_rank = 0;

	if (root == NULL) {
		printf("Empty tree.\n");
		return;
	}
	queue = NULL;
	enqueue(root);
	while( queue != NULL ) {
		n = dequeue();
		if (n->parent != NULL && n == n->parent->pointers[0]) {
			new_rank = path_to_root( root, n );
			if (new_rank != rank) {
				rank = new_rank;
				printf("\n");
			}
		}
		if (verbose_output) 
		printf("(%x)", n);
		for (i = 0; i < n->num_keys; i++) {
			if (verbose_output)
			printf("%x ", n->pointers[i]);
			printf("%d ", n->keys[i]);
		}
		if (!n->is_leaf)
		for (i = 0; i <= n->num_keys; i++)
		enqueue((node *) n->pointers[i]);
		if (verbose_output) {
			if (n->is_leaf) 
			printf("%x ", n->pointers[order - 1]);
			else
			printf("%x ", n->pointers[n->num_keys]);
		}
		printf("| ");
	}
	printf("\n");
}

node *
find_leaf( node* root, int key, bool verbose ) 
{

	int i = 0;
	node * c = root;
	if (c == NULL) {
		if (verbose) 
			printf("Empty tree.\n");
		return c;
	}
	while (!c->is_leaf) {
		if (verbose) {
			printf("[");
			for (i = 0; i < c->num_keys - 1; i++)
				printf("%d ", c->keys[i]);
			printf("%d] ", c->keys[i]);
		}
		i = 0;
		while (i < c->num_keys) {
			if (key >= c->keys[i]) 
				i++;
			else 
				break;
		}
		if (verbose)
			printf("%d ->\n", i);
		c = (node *)c->pointers[i];
	}
	if (verbose) {
		printf("Leaf [");
		for (i = 0; i < c->num_keys - 1; i++)
			printf("%d ", c->keys[i]);
		printf("%d] ->\n", c->keys[i]);
	}
	return c;

}

record *
find( node* root, int key, bool verbose ) 
{

	int i = 0;
	node * c = find_leaf( root, key, verbose );
	if (c == NULL) 
		return NULL;
	for (i = 0; i < c->num_keys; i++)
		if (c->keys[i] == key) 
			break;
	if (i == c->num_keys) 
		return NULL;
	else
		return (record *)c->pointers[i];

}

