#include <stdlib.h>
#include <stdio.h>

#include "../common.h"

#include "../util/timer/timer.h"

#include "./kernel/kernel_cpu.h"
#include "./kernel/kernel_cpu_2.h"

extern void setdevice(void);
extern void checkCUDAError(const char *msg);

__global__ void kernel_gpu(
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans,
    int threadsPerBlock)
{
    int bid = blockIdx.x;
    if (bid >= count) return;

    int thid = threadIdx.x;
    int i;

    for (i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((knodes[currKnode[bid]].keys[thid] <= keys[bid]) && 
                (knodes[currKnode[bid]].keys[thid+1] > keys[bid])) {

                if (knodes[offset[bid]].indices[thid] < knodes_elem) {
                    offset[bid] = knodes[offset[bid]].indices[thid];
                }
            }
        }

        if (thid == 0) {
            currKnode[bid] = offset[bid];
        }
    }

    if (thid < threadsPerBlock) {
        if (knodes[currKnode[bid]].keys[thid] == keys[bid]) {
            ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
        }
    }
}

__global__ void kernel_gpu_2(
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    long *lastKnode,
    long *offset_2,
    int *start,
    int *end,
    int *recstart,
    int *reclength,
    int threadsPerBlock)
{
    int bid = blockIdx.x;
    if (bid >= count) return;

    int thid = threadIdx.x;
    int i;

    for (i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((knodes[currKnode[bid]].keys[thid] <= start[bid]) && 
                (knodes[currKnode[bid]].keys[thid+1] > start[bid])) {

                if (knodes[currKnode[bid]].indices[thid] < knodes_elem) {
                    offset[bid] = knodes[currKnode[bid]].indices[thid];
                }
            }
            if ((knodes[lastKnode[bid]].keys[thid] <= end[bid]) && 
                (knodes[lastKnode[bid]].keys[thid+1] > end[bid])) {

                if (knodes[lastKnode[bid]].indices[thid] < knodes_elem) {
                    offset_2[bid] = knodes[lastKnode[bid]].indices[thid];
                }
            }
        }

        if (thid == 0) {
            currKnode[bid] = offset[bid];
            lastKnode[bid] = offset_2[bid];
        }
    }

    if (thid < threadsPerBlock) {
        if (knodes[currKnode[bid]].keys[thid] == start[bid]) {
            recstart[bid] = knodes[currKnode[bid]].indices[thid];
        }
    }

    if (thid < threadsPerBlock) {
        if (knodes[lastKnode[bid]].keys[thid] == end[bid]) {
            reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
        }
    }
}

void 
kernel_gpu_cuda_wrapper(record *records,
						long records_mem,
						knode *knodes,
						long knodes_elem,
						long knodes_mem,
						int order,
						long maxheight,
						int count,
						long *currKnode,
						long *offset,
						int *keys,
						record *ans)
{
    long long time0;
    long long time1;
    long long time2;

    time0 = get_time();

    setdevice();

    int threadsPerBlock = order < 1024 ? order : 1024;
    int blocksPerGrid = count;

    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaMalloc(&d_records, records_mem);
    cudaMalloc(&d_knodes, knodes_mem);
    cudaMalloc(&d_currKnode, count * sizeof(long));
    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMalloc(&d_keys, count * sizeof(int));
    cudaMalloc(&d_ans, count * sizeof(record));

    cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_keys, keys, count * sizeof(int), cudaMemcpyHostToDevice);

    time1 = get_time();

    kernel_gpu<<<blocksPerGrid, threadsPerBlock>>>(
        d_records,
        d_knodes,
        knodes_elem,
        order,
        maxheight,
        count,
        d_currKnode,
        d_offset,
        d_keys,
        d_ans,
        threadsPerBlock
    );

    checkCUDAError("kernel launch");
    cudaDeviceSynchronize();

    cudaMemcpy(ans, d_ans, count * sizeof(record), cudaMemcpyDeviceToHost);

    time2 = get_time();

    printf("Time spent in different stages of GPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : GPU: SET DEVICE\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time2-time0) * 100);
    printf("%15.12f s, %15.12f % : GPU: KERNEL\n", (float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time2-time0) * 100);

    printf("Total time:\n");
    printf("%.12f s\n", (float) (time2-time0) / 1000000);

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);
}

