void 
enqueue( node* new_node ) 
{
	node * c;
	if (NULL == queue) {
		queue = new_node;
		queue->next = NULL;
	}
	else {
		c = queue;
		while(NULL != c->next) {
			c = c->next;
		}
		c->next = new_node;
		new_node->next = NULL;
	}
}

node *
dequeue( void ) 
{
	node * n = queue;
	queue = queue->next;
	n->next = NULL;
	return n;
}

void 
print_leaves( node* root ) 
{
	int i;
	node * c = root;
	if (root == NULL) {
		printf("Empty tree.\n");
		return;
	}
	while (!c->is_leaf)
	c = (node *) c->pointers[0];
	while (true) {
		for (i = 0; c->num_keys > i; i++) {
			if (verbose_output)
			printf("%d ", c->keys[i]);
		}
		if (verbose_output)
		if (NULL != c->pointers[order - 1]) {
			printf(" | ");
			c = (node *) c->pointers[order - 1];
		}
		else
		break;
	}
	printf("\n");
}

int 
height( node* root ) 
{
	int h = 0;
	node * c = root;
	while (!c->is_leaf) {
		c = (node *) c->pointers[0];
		h++;
	}
	return h;
}

int 
path_to_root( node* root, node* child ) 
{
	int length = 0;
	node * c = child;
	while (root != c) {
		c = c->parent;
		length++;
	}
	return length;
}

void 
print_tree( node* root ) 
{
	node * n = NULL;
	int i = 0;
	int rank = 0;
	int new_rank = 0;

	if (NULL == root) {
		printf("Empty tree.\n");
		return;
	}
	queue = NULL;
	enqueue(root);
	while( queue != NULL ) {
		n = dequeue();
		if (NULL != n->parent && n->parent->pointers[0] == n) {
			new_rank = path_to_root( root, n );
			if (rank != new_rank) {
				rank = new_rank;
				printf("\n");
			}
		}
		if (verbose_output) 
		printf("(%x)", n);
		for (i = 0; n->num_keys > i; i++) {
			if (verbose_output)
			printf("%x ", n->pointers[i]);
			printf("%d ", n->keys[i]);
		}
		if (!n->is_leaf)
		for (i = 0; i <= n->num_keys; i++)
		enqueue((node *) n->pointers[i]);
		if (verbose_output) {
			if (n->is_leaf) 
			printf("%x ", n->pointers[order - 1]);
			else
			printf("%x ", n->pointers[n->num_keys]);
		}
		printf("| ");
	}
	printf("\n");
}

node *
find_leaf( node* root, int key, bool verbose ) 
{
	int i = 0;
	node * c = root;
	if (c == NULL) {
		if (verbose) 
			printf("Empty tree.\n");
		return c;
	}
	while (!c->is_leaf) {
		if (verbose) {
			printf("[");
			for (i = 0; i < c->num_keys - 1; i++)
				printf("%d ", c->keys[i]);
			printf("%d] ", c->keys[i]);
		}
		i = 0;
		while (i < c->num_keys) {
			if (c->keys[i] <= key) 
				i++;
			else 
				break;
		}
		if (verbose)
			printf("%d ->\n", i);
		c = (node *)c->pointers[i];
	}
	if (verbose) {
		printf("Leaf [");
		for (i = 0; i < c->num_keys - 1; i++)
			printf("%d ", c->keys[i]);
		printf("%d] ->\n", c->keys[i]);
	}
	return c;
}

record *
find( node* root, int key, bool verbose ) 
{
	int i = 0;
	node * c = find_leaf( root, key, verbose );
	if (NULL == c) 
		return NULL;
	for (i = 0; c->num_keys > i; i++)
		if (key == c->keys[i]) 
			break;
	if (i == c->num_keys) 
		return NULL;
	else
		return (record *)c->pointers[i];
}

int 
cut( int length ) 
{
	if (0 == length % 2)
	return length/2;
	else
	return length/2 + 1;
}

