#include <cuda.h>
#include <stdlib.h>
#include <stdio.h>

#include "../common.h"

#include "../util/timer/timer.h"

__global__ void kernel_gpu_wrapper(
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans,
    int threadsPerBlock)
{
    int bid = blockIdx.x;
    int thid = threadIdx.x;

    if (bid >= count) return;

    long local_currKnode = currKnode[bid];
    long local_offset = offset[bid];
    int local_key = keys[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((knodes[local_currKnode].keys[thid] <= local_key) && 
                (knodes[local_currKnode].keys[thid+1] > local_key)) {
                if (knodes[local_offset].indices[thid] < knodes_elem) {
                    local_offset = knodes[local_offset].indices[thid];
                }
            }
        }
        if (thid == 0) {
            local_currKnode = local_offset;
        }
    }

    if (thid < threadsPerBlock) {
        if (local_key == knodes[local_currKnode].keys[thid]) {
            ans[bid].value = records[knodes[local_currKnode].indices[thid]].value;
        }
    }
}

void 
kernel_gpu_cuda_wrapper(record *records,
						long records_mem,
						knode *knodes,
						long knodes_elem,
						long knodes_mem,
						int order,
						long maxheight,
						int count,
						long *currKnode,
						long *offset,
						int *keys,
						record *ans)
{
    long long time0;
    long long time1;
    long long time2;

    time0 = get_time();

    setdevice();

    int threadsPerBlock = order < 1024 ? order : 1024;
    int blocksPerGrid = count;

    time1 = get_time();

    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaMalloc(&d_records, records_mem);
    cudaMalloc(&d_knodes, knodes_mem);
    cudaMalloc(&d_currKnode, count * sizeof(long));
    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMalloc(&d_keys, count * sizeof(int));
