__global__ void layerforward_kernel(float *l1, float *l2, float *conn_flat, int n1, int n2) {
  int j = blockIdx.x * blockDim.x + threadIdx.x;
  if (j >= 1 && j <= n2) {
    float sum = 0.0;
    for (int k = 0; k <= n1; k++) {
      sum += conn_flat[k * (n2 + 1) + j] * l1[k];
    }
    l2[j] = 1.0 / (1.0 + exp(-sum));
  }
}

void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2) {
  l1[0] = 1.0;

  int rows = n1 + 1;
  int cols = n2 + 1;
  float *conn_flat;
  cudaMalloc(&conn_flat, rows * cols * sizeof(float));

  for (int i = 0; i <= n1; i++) {
    cudaMemcpy(conn_flat + i * cols, conn[i], cols * sizeof(float), cudaMemcpyHostToDevice);
  }

  float *d_l1, *d_l2;
  cudaMalloc(&d_l1, (n1 + 1) * sizeof(float));
  cudaMalloc(&d_l2, (n2 + 1) * sizeof(float));

  cudaMemcpy(d_l1, l1, (n1 + 1) * sizeof(float), cudaMemcpyHostToDevice);

  int threads = 256;
  int blocks = (n2 + threads) / threads;
  layerforward_kernel<<<blocks, threads>>>(d_l1, d_l2, conn_flat, n1, n2);

  cudaMemcpy(l2, d_l2, (n2 + 1) * sizeof(float), cudaMemcpyDeviceToHost);

  cudaFree(conn_flat);
  cudaFree(d_l1);
  cudaFree(d_l2);
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err) {
  int j;
  float o, t, errsum;
  errsum = 0.0;
  for (j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0 - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err) {
  int j, k;
  float h, sum, errsum;

  errsum = 0.0;
  for (j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0;
    for (k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0 - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

__global__ void adjust_weights_kernel(float *delta, float *ly, float *w_flat, float *oldw_flat, int ndelta, int nly) {
  int j = blockIdx.x * blockDim.x + threadIdx.x;
