    for (int k = 0; k <= nly; k++) {
      float new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw_flat[k * (ndelta + 1) + j]));
      w_flat[k * (ndelta + 1) + j] += new_dw;
      oldw_flat[k * (ndelta + 1) + j] = new_dw;
