static fp* get_frame_host(avi_t* cell_file, int frame_num, int cropped, int scaled, int converted) {
	long len;
	int keyframe;
	char* vidbuf = (char*)malloc(cell_file->width * cell_file->height * 3);
	AVI_set_video_position(cell_file, frame_num);
	len = AVI_read_frame(cell_file, vidbuf, &keyframe);

	fp* image = (fp*)malloc(cell_file->width * cell_file->height * sizeof(fp));
	int h = cell_file->height;
	int w = cell_file->width;

	for(int y=0; y<h; y++){
		for(int x=0; x<w; x++){
			int idx = (y * w + x) * 3;
			int r = vidbuf[idx];
			int g = vidbuf[idx+1];
			int b = vidbuf[idx+2];
			image[y*w+x] = (r + g + b) / 3.0f;
		}
	}
	free(vidbuf);
	return image;
}

