#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE	256

#define MAX_PD	(3.0e6)

#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100

#define FACTOR_CHIP	0.5

typedef float FLOAT;

const FLOAT t_chip = 0.0005;
const FLOAT chip_height = 0.016;
const FLOAT chip_width = 0.016;

const FLOAT amb_temp = 80.0;

__global__ void single_iteration_kernel(FLOAT *result, FLOAT *temp, FLOAT *power, int row, int col,
                                      FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1)
{
    int r_idx = blockIdx.y * BLOCK_SIZE_R + threadIdx.y;
    int c_idx = blockIdx.x * BLOCK_SIZE_C + threadIdx.x;

    if (r_idx >= row || c_idx >= col) return;

    FLOAT delta;
    int r = r_idx;
    int c = c_idx;

    if ( (r == 0) && (c == 0) ) {
        delta = (Cap_1) * (power[0] +
            (temp[1] - temp[0]) * Rx_1 +
            (temp[col] - temp[0]) * Ry_1 +
            (amb_temp - temp[0]) * Rz_1);
    }	
    else if ((r == 0) && (c == col-1)) {
        delta = (Cap_1) * (power[c] +
            (temp[c-1] - temp[c]) * Rx_1 +
            (temp[c+col] - temp[c]) * Ry_1 +
            (amb_temp - temp[c]) * Rz_1);
    }	
    else if ((r == row-1) && (c == col-1)) {
        delta = (Cap_1) * (power[r*col+c] + 
            (temp[r*col+c-1] - temp[r*col+c]) * Rx_1 + 
            (temp[(r-1)*col+c] - temp[r*col+c]) * Ry_1 + 
            (amb_temp - temp[r*col+c]) * Rz_1);					
    }	
    else if ((r == row-1) && (c == 0)) {
        delta = (Cap_1) * (power[r*col] + 
            (temp[r*col+1] - temp[r*col]) * Rx_1 + 
            (temp[(r-1)*col] - temp[r*col]) * Ry_1 + 
            (amb_temp - temp[r*col]) * Rz_1);
    }	
    else if (r == 0) {
        delta = (Cap_1) * (power[c] + 
            (temp[c+1] + temp[c-1] - 2.0*temp[c]) * Rx_1 + 
            (temp[col+c] - temp[c]) * Ry_1 + 
            (amb_temp - temp[c]) * Rz_1);
    }	
    else if (c == col-1) {
        delta = (Cap_1) * (power[r*col+c] + 
            (temp[(r+1)*col+c] + temp[(r-1)*col+c] - 2.0*temp[r*col+c]) * Ry_1 + 
            (temp[r*col+c-1] - temp[r*col+c]) * Rx_1 + 
            (amb_temp - temp[r*col+c]) * Rz_1);
    }	
    else if (r == row-1) {
        delta = (Cap_1) * (power[r*col+c] + 
            (temp[r*col+c+1] + temp[r*col+c-1] - 2.0*temp[r*col+c]) * Rx_1 + 
            (temp[(r-1)*col+c] - temp[r*col+c]) * Ry_1 + 
            (amb_temp - temp[r*col+c]) * Rz_1);
    }	
    else if (c == 0) {
        delta = (Cap_1) * (power[r*col] + 
            (temp[(r+1)*col] + temp[(r-1)*col] - 2.0*temp[r*col]) * Ry_1 + 
