            (amb_temp - temp[r*col+c]) * Rz_1);
    }

    result[r*col+c] = temp[r*col+c] + delta;
}

void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col) 
{
    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0;

    FLOAT Rx_1=1.f/Rx;
    FLOAT Ry_1=1.f/Ry;
    FLOAT Rz_1=1.f/Rz;
    FLOAT Cap_1 = step/Cap;

    int array_size = row*col;
    size_t bytes = array_size * sizeof(FLOAT);

    FLOAT *d_temp, *d_power, *d_result;
    cudaMalloc(&d_temp, bytes);
    cudaMalloc(&d_power, bytes);
    cudaMalloc(&d_result, bytes);

    cudaMemcpy(d_temp, temp, bytes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_power, power, bytes, cudaMemcpyHostToDevice);

    dim3 block(BLOCK_SIZE_C, BLOCK_SIZE_R);
    dim3 grid((col + BLOCK_SIZE_C - 1) / BLOCK_SIZE_C, (row + BLOCK_SIZE_R - 1) / BLOCK_SIZE_R);

    FLOAT *current_temp = d_temp;
    FLOAT *current_result = d_result;

    for (int i = 0; i < num_iterations; i++)
    {
        single_iteration_kernel<<<grid, block>>>(current_result, current_temp, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);
        cudaDeviceSynchronize();

        FLOAT *tmp = current_temp;
        current_temp = current_result;
        current_result = tmp;
    }

    cudaMemcpy(result, current_temp, bytes, cudaMemcpyDeviceToHost);

    cudaFree(d_temp);
    cudaFree(d_power);
    cudaFree(d_result);
}

void fatal(const char *s)
{
