        single_iteration_kernel<<<grid, block>>>(current_result, current_temp, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);

        // Swap pointers for next iteration
        FLOAT *tmp = current_temp;
        current_temp = current_result;
        current_result = tmp;
    }

    // Copy result back to host. 
    // Note: After the loop, current_result points to the buffer that holds the final result.
    // If num_iterations is odd, current_result is d_temp. If even, it is d_result.
    // The original code logic: if (1&sim_time) ? result : temp. 
    // We need to copy the final computed data into the host 'result' array passed to this function.

    if (num_iterations % 2 == 1) {
        // Final data is in d_temp (because we swapped at end of last iter)
        cudaMemcpy(result, d_temp, bytes, cudaMemcpyDeviceToHost);
    } else {
        // Final data is in d_result
        cudaMemcpy(result, d_result, bytes, cudaMemcpyDeviceToHost);
    }

    cudaFree(d_temp);
    cudaFree(d_power);
    cudaFree(d_result);
}

