__global__ void computeTempKernel(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, float ce, float cw, float cn, float cs, float ct, float cb, float cc, float amb_temp_val) 
{
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;
    int z = blockIdx.z * blockDim.z + threadIdx.z;

    if (x < nx && y < ny && z < nz) {
        int c = x + y * nx + z * nx * ny;

        int w = (x == 0) ? c : c - 1;
        int e = (x == nx - 1) ? c : c + 1;
        int n = (y == 0) ? c : c - nx;
        int s = (y == ny - 1) ? c : c + nx;
        int b = (z == 0) ? c : c - nx * ny;
        int t = (z == nz - 1) ? c : c + nx * ny;

        tOut[c] = tIn[c]*cc + tIn[n]*cn + tIn[s]*cs + tIn[e]*ce + tIn[w]*cw + tIn[t]*ct + tIn[b]*cb + (dt/Cap) * pIn[c] + ct*amb_temp_val;
    }
}

void computeTempCUDA(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, int numiter) 
{   
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;
    cc = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

    float *d_pIn, *d_tIn, *d_tOut;
    size_t size = nx * ny * nz * sizeof(float);

    cudaMalloc(&d_pIn, size);
    cudaMalloc(&d_tIn, size);
    cudaMalloc(&d_tOut, size);

    cudaMemcpy(d_pIn, pIn, size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_tIn, tIn, size, cudaMemcpyHostToDevice);

    dim3 block(16, 16, 4);
    dim3 grid((nx + block.x - 1) / block.x, 
              (ny + block.y - 1) / block.y, 
              (nz + block.z - 1) / block.z);

    for (int i = 0; i < numiter; i++) {
        computeTempKernel<<<grid, block>>>(d_pIn, d_tIn, d_tOut, 
                                           nx, ny, nz, Cap, 
                                           Rx, Ry, Rz, 
                                           dt, ce, cw, cn, cs, ct, cb, cc, amb_temp);

        float *temp = d_tIn;
        d_tIn = d_tOut;
        d_tOut = temp;
    }

    cudaMemcpy(tOut, d_tIn, size, cudaMemcpyDeviceToHost);

    cudaFree(d_pIn);
    cudaFree(d_tIn);
    cudaFree(d_tOut);
}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0; 
    int i;
    for(i = 0; i < len; i++)
    {
        err += (arr1[i]-arr2[i]) * (arr1[i]-arr2[i]);
    }

    return (float)sqrt(err/len);
}

