#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <float.h>

#include "kmeans.h"

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

__device__ float euclid_dist_2_device(float *pt1, float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

__device__ int find_nearest_point_device(float *pt, int nfeatures, float **pts, int npts) {
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < npts; i++) {
        float dist = euclid_dist_2_device(pt, pts[i], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

__global__ void kmeans_assign_clusters_kernel(float **feature,
                                              float **clusters,
                                              int *membership,
                                              int *partial_new_centers_len,
                                              float **partial_new_centers,
                                              int npoints,
                                              int nclusters,
                                              int nfeatures,
                                              int tid_offset) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= npoints) return;

    int tid = blockIdx.y; 

    int index = find_nearest_point_device(feature[i], nfeatures, clusters, nclusters);

    if (membership[i] != index) {
        atomicAdd(&partial_new_centers_len[tid_offset + index], 1);
    }

    membership[i] = index;

    partial_new_centers_len[tid_offset + index]++;
    for (int j = 0; j < nfeatures; j++) {
        partial_new_centers[tid_offset + index][j] += feature[i][j];
    }
}

float** kmeans_clustering(float **feature,
                          int nfeatures,
                          int npoints,
                          int nclusters,
                          float threshold,
                          int *membership) {
    int i, j, k, n = 0, loop = 0;
    int *new_centers_len;
    float **new_centers;
    float **clusters;
    float delta;

    int nthreads = 1; 

    clusters = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*) malloc(nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    for (i = 0; i < nclusters; i++) {
        for (j = 0; j < nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    for (i = 0; i < npoints; i++)
        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));

    new_centers = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*) calloc(nclusters * nfeatures, sizeof(float));
    for (i = 1; i < nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    int **partial_new_centers_len;
    float ***partial_new_centers;

    partial_new_centers_len = (int**) malloc(nthreads * sizeof(int*));
    partial_new_centers_len[0] = (int*) calloc(nthreads * nclusters, sizeof(int));
    for (i = 1; i < nthreads; i++)
        partial_new_centers_len[i] = partial_new_centers_len[i-1] + nclusters;

    partial_new_centers = (float**) malloc(nthreads * sizeof(float*));
    partial_new_centers[0] = (float*) malloc(nthreads * nclusters * sizeof(float*));
    for (i = 1; i < nthreads; i++)
        partial_new_centers[i] = partial_new_centers[i-1] + nclusters;

    for (i = 0; i < nthreads; i++) {
        for (j = 0; j < nclusters; j++)
            partial_new_centers[i][j] = (float*) calloc(nfeatures, sizeof(float));
    }

    printf("num of threads = %d\n", nthreads);

    float **d_feature;
    float **d_clusters;
    int *d_membership;
    int *d_partial_new_centers_len;
    float **d_partial_new_centers;

    cudaMalloc(&d_feature, npoints * sizeof(float*));
    cudaMalloc(&d_clusters, nclusters * sizeof(float*));
    cudaMalloc(&d_membership, npoints * sizeof(int));
    cudaMalloc(&d_partial_new_centers_len, nthreads * nclusters * sizeof(int));
    cudaMalloc(&d_partial_new_centers, nthreads * nclusters * sizeof(float*));

    float *d_feature_data;
    cudaMalloc(&d_feature_data, npoints * nfeatures * sizeof(float));
    cudaMemcpy(d_feature_data, feature[0], npoints * nfeatures * sizeof(float), cudaMemcpyHostToDevice);

    float *d_feature_pointers[npoints];
    for(i=0; i<npoints; i++) d_feature_pointers[i] = d_feature_data + i * nfeatures;
    cudaMemcpy(d_feature, d_feature_pointers, npoints * sizeof(float*), cudaMemcpyHostToDevice);

    float *d_clusters_data;
    cudaMalloc(&d_clusters_data, nclusters * nfeatures * sizeof(float));

    float *d_clusters_pointers[nclusters];
    for(i=0; i<nclusters; i++) d_clusters_pointers[i] = d_clusters_data + i * nfeatures;
    cudaMemcpy(d_clusters, d_clusters_pointers, nclusters * sizeof(float*), cudaMemcpyHostToDevice);
    cudaMemcpy(d_clusters_data, clusters[0], nclusters * nfeatures * sizeof(float), cudaMemcpyHostToDevice);

    cudaMemcpy(d_membership, membership, npoints * sizeof(int), cudaMemcpyHostToDevice);

    int block_size = 256;
    dim3 dim_block(block_size);
    dim3 dim_grid((npoints + block_size - 1) / block_size, nthreads);

    do {
        delta = 0.0;

        cudaMemcpy(d_partial_new_centers_len, partial_new_centers_len[0], nthreads * nclusters * sizeof(int), cudaMemcpyHostToDevice);

        float *d_partial_pointers[nthreads * nclusters];
        for(i=0; i<nthreads*nclusters; i++) {
            int c = i % nclusters;
            int t = i / nclusters;
            d_partial_pointers[i] = partial_new_centers[t][c]; 
        }

        float **d_partial_host = (float**) malloc(nthreads * nclusters * sizeof(float*));
        for(i=0; i<nthreads*nclusters; i++) {
            int c = i % nclusters;
            int t = i / nclusters;
            d_partial_host[i] = partial_new_centers[t][c];
        }
        cudaMemcpy(d_partial_new_centers, d_partial_host, nthreads * nclusters * sizeof(float*), cudaMemcpyHostToDevice);
        free(d_partial_host);

        kmeans_assign_clusters_kernel<<<dim_grid, dim_block>>>(d_feature, d_clusters, d_membership,
                                                               d_partial_new_centers_len,
                                                               d_partial_new_centers,
                                                               npoints, nclusters, nfeatures, 0);

        cudaDeviceSynchronize();

        int *h_partial_len = (int*) malloc(nthreads * nclusters * sizeof(int));
        float *h_partial_centers = (float*) malloc(nthreads * nclusters * nfeatures * sizeof(float));

        cudaMemcpy(h_partial_len, d_partial_new_centers_len, nthreads * nclusters * sizeof(int), cudaMemcpyDeviceToHost);

        float *h_partial_ptrs[nthreads * nclusters];
        cudaMemcpy(h_partial_ptrs, d_partial_new_centers, nthreads * nclusters * sizeof(float*), cudaMemcpyDeviceToHost);

        for(i=0; i<nthreads*nclusters; i++) {
            cudaMemcpy(h_partial_centers + i * nfeatures, h_partial_ptrs[i], nfeatures * sizeof(float), cudaMemcpyDeviceToHost);
        }

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nthreads; j++) {
                new_centers_len[i] += h_partial_len[j * nclusters + i];
                for (k = 0; k < nfeatures; k++) {
                    new_centers[i][k] += h_partial_centers[(j * nclusters + i) * nfeatures + k];
                }
            }
        }

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];
                new_centers[i][j] = 0.0;
            }
            new_centers_len[i] = 0;
        }

        cudaMemcpy(d_clusters_data, clusters[0], nclusters * nfeatures * sizeof(float), cudaMemcpyHostToDevice);

        loop++;
    } while (delta > threshold && loop < 500);

    cudaFree(d_feature);
    cudaFree(d_feature_data);
    cudaFree(d_clusters);
    cudaFree(d_clusters_data);
    cudaFree(d_membership);
    cudaFree(d_partial_new_centers_len);
    cudaFree(d_partial_new_centers);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    for (i = 0; i < nthreads; i++) {
        for (j = 0; j < nclusters; j++)
            free(partial_new_centers[i][j]);
    }
    free(partial_new_centers[0]);
    free(partial_new_centers);
    free(partial_new_centers_len[0]);
    free(partial_new_centers_len);

    return clusters;
}

int cluster(int numObjects,
            int numAttributes,
            float **attributes,
            int nclusters,
            float threshold,
            float ***cluster_centres) {
    int *membership;
    float **tmp_cluster_centres;

    membership = (int*) malloc(numObjects * sizeof(int));

    srand(7);

    tmp_cluster_centres = kmeans_clustering(attributes,
                                            numAttributes,
                                            numObjects,
                                            nclusters,
                                            threshold,
                                            membership);

    if (*cluster_centres) {
        free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    free(membership);

    return 0;
}

