#ifdef __cplusplus
extern "C" {
#endif

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdlib.h>
#include <stdio.h>
#include <math.h>
#include <time.h>
#include <sys/time.h>

#define fp double
#define NUMBER_PAR_PER_BOX 100
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct {
    fp alpha;
} par_str;

typedef struct {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

static long long get_time_local() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

__global__ void kernel_gpu(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    int l = blockIdx.x;
    if (l >= dim.number_boxes) return;

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    long first_i = box[l].offset;
    FOUR_VECTOR* rA = &rv[first_i];
    FOUR_VECTOR* fA = &fv[first_i];

    for (int k = 0; k < (1 + box[l].nn); k++) {
        int pointer;
        if (k == 0) {
            pointer = l;
        } else {
            pointer = box[l].nei[k-1].number;
        }

        long first_j = box[pointer].offset;
        FOUR_VECTOR* rB = &rv[first_j];
        fp* qB = &qv[first_j];

        for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            FOUR_VECTOR fA_i = fA[i];
            FOUR_VECTOR rA_i = rA[i];

            for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                FOUR_VECTOR rB_j = rB[j];
                fp qB_j = qB[j];

                fp r2 = rA_i.v + rB_j.v - DOT(rA_i, rB_j);
                fp u2 = a2 * r2;
                fp vij = exp(-u2);
                fp fs = 2.0 * vij;

                THREE_VECTOR d;
                d.x = rA_i.x - rB_j.x;
                d.y = rA_i.y - rB_j.y;
                d.z = rA_i.z - rB_j.z;

                fp fxij = fs * d.x;
                fp fyij = fs * d.y;
                fp fzij = fs * d.z;

                fA_i.v += qB_j * vij;
                fA_i.x += qB_j * fxij;
                fA_i.y += qB_j * fyij;
                fA_i.z += qB_j * fzij;
            }
            fA[i] = fA_i;
        }
    }
}

void kernel_cpu(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    long long time0 = get_time_local();
    long long time1 = get_time_local();
    long long time2;
    long long time3 = get_time_local();

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    // Allocate device memory
    box_str* d_box;
    FOUR_VECTOR* d_rv;
    fp* d_qv;
    FOUR_VECTOR* d_fv;

    cudaMalloc(&d_box, dim.box_mem);
    cudaMalloc(&d_rv, dim.space_mem);
    cudaMalloc(&d_qv, dim.space_mem2);
    cudaMalloc(&d_fv, dim.space_mem);

    cudaMemcpy(d_box, box, dim.box_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_rv, rv, dim.space_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_qv, qv, dim.space_mem2, cudaMemcpyHostToDevice);
    cudaMemcpy(d_fv, fv, dim.space_mem, cudaMemcpyHostToDevice);

    time2 = get_time_local();

    // Launch kernel
    kernel_gpu<<<dim.number_boxes, 1>>>(par, dim, d_box, d_rv, d_qv, d_fv);
    cudaDeviceSynchronize();

    long long time4 = get_time_local();

    // Copy results back
    cudaMemcpy(fv, d_fv, dim.space_mem, cudaMemcpyDeviceToHost);

    cudaFree(d_box);
    cudaFree(d_rv);
    cudaFree(d_qv);
    cudaFree(d_fv);

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : CPU/MCPU: VARIABLES\n",
           (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time4 - time0) * 100);
    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n",
           (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time4 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: INPUTS\n",
           (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time4 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n",
           (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time4 - time0) * 100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time4 - time0) / 1000000);
}

