    long long time1, time2, time3, time4;

    time1 = get_time_local();

    setdevice();

    time2 = get_time_local();

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    time3 = get_time_local();

    FOUR_VECTOR* d_rv;
    fp* d_qv;
    FOUR_VECTOR* d_fv;
    box_str* d_box;

    cudaMalloc(&d_rv, dim.space_mem);
    cudaMalloc(&d_qv, dim.space_mem2);
    cudaMalloc(&d_fv, dim.space_mem);
    cudaMalloc(&d_box, dim.box_mem);

    cudaMemcpy(d_rv, rv, dim.space_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_qv, qv, dim.space_mem2, cudaMemcpyHostToDevice);
    cudaMemcpy(d_fv, fv, dim.space_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_box, box, dim.box_mem, cudaMemcpyHostToDevice);

    dim3 blockDim(NUMBER_THREADS);
