extern void
lud_cuda(float *m, int matrix_dim);

#define BS 16

__global__ void lud_diagonal_kernel(float *a, int size, int offset) {
    int i = 0; 
    if (i == 0) {
        for (i = 0; i < BS; i++) {
            for (int j = i; j < BS; j++) {
                float sum = 0.0f;
                for (int k = 0; k < i; k++) {
                    sum += a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
                }
                a[(offset + i) * size + (offset + j)] -= sum;
            }

            float temp = 1.0f / a[(offset + i) * size + (offset + i)];
            for (int j = i + 1; j < BS; j++) {
                float sum = 0.0f;
                for (int k = 0; k < i; k++) {
                    sum += a[(offset + j) * size + (offset + k)] * a[(offset + k) * size + (offset + i)];
                }
                a[(offset + j) * size + (offset + i)] = (a[(offset + j) * size + (offset + i)] - sum) * temp;
            }
        }
    }
}

__global__ void lud_inter_row_kernel(float *a, int size, int offset, int chunks_in_inter_row) {
    int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (chunk_idx >= chunks_in_inter_row) return;

    int i_global = offset;
    int j_global = offset + BS * (chunk_idx + 1);

    float temp[BS * BS];
    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            temp[i * BS + j] = a[(i + offset) * size + (offset + j)];
        }
    }

    for (int j = 0; j < BS; j++) {
        for (int i = 0; i < BS; i++) {
            float sum = 0.0f;
            for (int k = 0; k < i; k++) {
                sum += temp[i * BS + k] * a[(i_global + k) * size + (j_global + j)];
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            a[i_here * size + j_here] -= sum;
        }
    }
}

__global__ void lud_inter_col_kernel(float *a, int size, int offset, int chunks_in_inter_row) {
    int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (chunk_idx >= chunks_in_inter_row) return;

    int i_global = offset + BS * (chunk_idx + 1);
    int j_global = offset;

    float temp[BS * BS];
    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            temp[i * BS + j] = a[(i + offset) * size + (offset + j)];
        }
    }

    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            float sum = 0.0f;
            for (int k = 0; k < j; k++) {
                sum += a[(i_global + i) * size + (j_global + k)] * temp[k * BS + j];
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            float div = a[(offset + j) * size + (offset + j)];
            a[i_here * size + j_here] = (a[i_here * size + j_here] - sum) / div;
        }
    }
}

__global__ void lud_inter_block_kernel(float *a, int size, int offset, int chunks_in_inter_row, int chunks_per_inter) {
    int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (chunk_idx >= chunks_per_inter) return;

    int row_idx = chunk_idx / chunks_in_inter_row;
    int col_idx = chunk_idx % chunks_in_inter_row;

    int i_global = offset + BS * (1 + row_idx);
    int j_global = offset + BS * (1 + col_idx);

    float temp_top[BS * BS];
    float temp_left[BS * BS];

    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            temp_top[i * BS + j] = a[(i + offset) * size + (j_global + j)];
            temp_left[i * BS + j] = a[(i_global + i) * size + (offset + j)];
        }
    }

    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            float sum = 0.0f;
            for (int k = 0; k < BS; k++) {
                sum += temp_left[i * BS + k] * temp_top[k * BS + j];
            }
            a[(i_global + i) * size + (j_global + j)] -= sum;
        }
    }
}

void lud_cuda(float *a, int size) {
    int offset;
    int size_inter;
    int chunks_in_inter_row;
    int chunks_per_inter;

    float *d_a;
    cudaMalloc(&d_a, size * size * sizeof(float));
    cudaMemcpy(d_a, a, size * size * sizeof(float), cudaMemcpyHostToDevice);

    for (offset = 0; offset < size - BS; offset += BS) {
        // Diagonal block
        lud_diagonal_kernel<<<1, 1>>>(d_a, size, offset);

        size_inter = size - offset - BS;
        chunks_in_inter_row = size_inter / BS;

        // Inter-row (Right)
        if (chunks_in_inter_row > 0) {
            int threads = 256;
            int blocks = (chunks_in_inter_row + threads - 1) / threads;
            lud_inter_row_kernel<<<blocks, threads>>>(d_a, size, offset, chunks_in_inter_row);
        }

        // Inter-col (Bottom)
        if (chunks_in_inter_row > 0) {
            int threads = 256;
            int blocks = (chunks_in_inter_row + threads - 1) / threads;
            lud_inter_col_kernel<<<blocks, threads>>>(d_a, size, offset, chunks_in_inter_row);
        }

        // Inter-block (Bottom-Right)
        chunks_per_inter = chunks_in_inter_row * chunks_in_inter_row;
        if (chunks_per_inter > 0) {
            int threads = 256;
            int blocks = (chunks_per_inter + threads - 1) / threads;
            lud_inter_block_kernel<<<blocks, threads>>>(d_a, size, offset, chunks_in_inter_row, chunks_per_inter);
        }
    }

    // Final diagonal block
    lud_diagonal_kernel<<<1, 1>>>(d_a, size, offset);

    cudaMemcpy(a, d_a, size * size * sizeof(float), cudaMemcpyDeviceToHost);
    cudaFree(d_a);
}

