#include <string.h>
#include <stdlib.h>
#include <stdio.h>
#include <time.h>
#include <math.h>

#include "common.h"

#define BS 16

static __device__ __forceinline__ float get_val(const float* a, int size, int i, int j) {
    return a[i * size + j];
}

static __device__ __forceinline__ void set_val(float* a, int size, int i, int j, float val) {
    a[i * size + j] = val;
}

__global__ void lud_diagonal_kernel(float* a, int size, int offset) {
    int i = offset + blockIdx.x;
    int j_start = i;
    int j_end = offset + BS;

    if (i >= size) return;

    // Compute diagonal block row
    for (int j = j_start; j < j_end && j < size; j++) {
        float sum = 0.0f;
        for (int k = offset; k < i; k++) {
            sum += get_val(a, size, i, k) * get_val(a, size, k, j);
        }
        set_val(a, size, i, j, get_val(a, size, i, j) - sum);
    }

    if (i < size) {
        float diag_val = get_val(a, size, i, i);
        if (diag_val != 0.0f) {
            float inv_diag = 1.0f / diag_val;

            // Compute diagonal block column
            for (int j = i + 1; j < j_end && j < size; j++) {
                float sum = 0.0f;
                for (int k = offset; k < i; k++) {
                    sum += get_val(a, size, j, k) * get_val(a, size, k, i);
                }
                float val = get_val(a, size, j, i) - sum;
                set_val(a, size, j, i, val * inv_diag);
            }
        }
    }
}

__global__ void lud_inter_row_kernel(float* a, int size, int offset) {
    int chunk_idx = blockIdx.x;
    int size_inter = size - offset - BS;
    int chunks_in_inter_row = size_inter / BS;

    if (chunk_idx >= chunks_in_inter_row) return;

    int i_global = offset;
    int j_global = offset + BS * (chunk_idx + 1);

    // Load temp block (top)
    float temp[BS * BS];
    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            if (i + offset < size && offset + j < size) {
                temp[i * BS + j] = get_val(a, size, i + offset, offset + j);
            } else {
                temp[i * BS + j] = 0.0f;
            }
        }
    }

    // Update right block
    for (int j = 0; j < BS; j++) {
        for (int i = 0; i < BS; i++) {
            float sum = 0.0f;
            for (int k = 0; k < i; k++) {
                sum += temp[i * BS + k] * get_val(a, size, i_global + k, j_global + j);
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            if (i_here < size && j_here < size) {
                set_val(a, size, i_here, j_here, get_val(a, size, i_here, j_here) - sum);
            }
        }
    }
}

__global__ void lud_inter_col_kernel(float* a, int size, int offset) {
    int chunk_idx = blockIdx.x;
    int size_inter = size - offset - BS;
    int chunks_in_inter_row = size_inter / BS;

    if (chunk_idx >= chunks_in_inter_row) return;

    int j_global = offset;
    int i_global = offset + BS * (chunk_idx + 1);

    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            float sum = 0.0f;
            for (int k = 0; k < j; k++) {
                sum += get_val(a, size, i_global + i, j_global + k) * get_val(a, size, offset + k, offset + j);
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            if (i_here < size && j_here < size) {
                float divisor = get_val(a, size, offset + j, offset + j);
                if (divisor != 0.0f) {
                    set_val(a, size, i_here, j_here, (get_val(a, size, i_here, j_here) - sum) / divisor);
                }
            }
        }
    }
}

__global__ void lud_inter_block_kernel(float* a, int size, int offset, int chunks_in_inter_row) {
    int chunk_idx = blockIdx.x;

    int row_idx = chunk_idx / chunks_in_inter_row;
    int col_idx = chunk_idx % chunks_in_inter_row;

    int i_global = offset + BS * (1 + row_idx);
    int j_global = offset + BS * (1 + col_idx);

    if (i_global >= size || j_global >= size) return;

    float temp_top[BS * BS];
    float temp_left[BS * BS];

    // Load blocks
    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            temp_top[i * BS + j] = (i + offset < size && j + j_global < size) ? get_val(a, size, i + offset, j + j_global) : 0.0f;
            temp_left[i * BS + j] = (i + i_global < size && j + offset < size) ? get_val(a, size, i + i_global, j + offset) : 0.0f;
        }
    }

    // Update block
    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            float sum = 0.0f;
            for (int k = 0; k < BS; k++) {
                sum += temp_left[i * BS + k] * temp_top[k * BS + j];
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            if (i_here < size && j_here < size) {
                set_val(a, size, i_here, j_here, get_val(a, size, i_here, j_here) - sum);
            }
        }
    }
}

void lud_cuda(float *a, int size) {
    int offset;

    for (offset = 0; offset < size - BS; offset += BS) {
        // 1. Diagonal block
        dim3 diag_blocks(BS, 1, 1);
        lud_diagonal_kernel<<<diag_blocks, 1>>>(a, size, offset);

        int size_inter = size - offset - BS;
        int chunks_in_inter_row = size_inter / BS;

        // 2. Inter-row (right)
        if (chunks_in_inter_row > 0) {
            lud_inter_row_kernel<<<chunks_in_inter_row, 1>>>(a, size, offset);
        }

        // 3. Inter-col (bottom)
        if (chunks_in_inter_row > 0) {
            lud_inter_col_kernel<<<chunks_in_inter_row, 1>>>(a, size, offset);
        }

        // 4. Inter-block (bottom-right)
        int chunks_per_inter = chunks_in_inter_row * chunks_in_inter_row;
        if (chunks_per_inter > 0) {
            lud_inter_block_kernel<<<chunks_per_inter, 1>>>(a, size, offset, chunks_in_inter_row);
        }

        cudaDeviceSynchronize();
    }

    // Final diagonal block if needed
    if (offset < size) {
        dim3 diag_blocks(BS, 1, 1);
        lud_diagonal_kernel<<<diag_blocks, 1>>>(a, size, offset);
        cudaDeviceSynchronize();
    }
}

