#if TREE_ACCESS_HISTOGRAM
                , ctx->ref->d_node_hist,
                ctx->ref->d_child_hist
#endif
				);
    }


	cudaError_t err = cudaGetLastError();
	if ( cudaSuccess != err) {
	    fprintf(stderr, "Kernel execution failed: %s.\n",
	            cudaGetErrorString(err));
	    exit(EXIT_FAILURE);
	}
}

