	++num_bind_tex_calls;													 \
} while(0)

#define CUDA_MALLOC(ptr, size) do {							 			 	 \
	cudaMalloc(ptr, size);													 \
	++num_bind_tex_calls;													 \
} while(0)

#define CUDA_MALLOC_PITCH(ptr, out_pitch, rowsize, numrows) do { 			 \
	cudaMallocPitch(ptr, out_pitch, rowsize, numrows);						 \
	++num_bind_tex_calls;													 \
} while(0)

#define CUDA_MALLOC_ARRAY(ptr, desc, pitch, rows) do {						 \
