	        childrentex.addressMode[0] = cudaAddressModeClamp;
	        childrentex.filterMode = cudaFilterModePoint;
	        childrentex.normalized = false;    

	        BIND_TEX(0, childrentex, (void*)(ref->d_children_tex_array), 
