	dim3 dimBlock(blocksize, 1, 1);

	dim3 dimGrid(ceil(numQueries / (float)BLOCKSIZE), 1, 1);


    if (doRC) {

        mummergpuRCKernel <<< dimGrid, dimBlock, 0 >>> (ctx->results.d_match_coords,
