#else 


        CUDA_MALLOC( (void**)(&ref->d_node_tex_array), 
                     ref->tex_node_height * sizeof(PixelOfNode));

        CUDA_SAFE_CALL( cudaMemcpy( (ref->d_node_tex_array),
                                           ref->h_node_tex_array,
                                           ref->tex_node_height * sizeof(PixelOfNode),
