// Helper function to parse float from string manually for device code
__device__ float parse_float_device(const char *str) {
    float result = 0.0f;
    float sign = 1.0f;
    float fraction = 0.0f;
    float divisor = 1.0f;
    int i = 0;
    int found_digit = 0;
    int found_dot = 0;

    // Skip whitespace
    while (str[i] == ' ' || str[i] == '\t') i++;

    // Handle sign
    if (str[i] == '-') {
        sign = -1.0f;
        i++;
    } else if (str[i] == '+') {
        i++;
    }

    // Parse integer part
    while (str[i] >= '0' && str[i] <= '9') {
        result = result * 10.0f + (str[i] - '0');
        i++;
        found_digit = 1;
    }

    // Parse fractional part
    if (str[i] == '.') {
        found_dot = 1;
        i++;
        while (str[i] >= '0' && str[i] <= '9') {
            fraction = fraction * 10.0f + (str[i] - '0');
            divisor *= 10.0f;
            i++;
            found_digit = 1;
        }
    }

    if (!found_digit) return 0.0f;

    return sign * (result + fraction / divisor);
}

__global__ void compute_distances(float *z, char *sandbox, int rec_count, float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
