// Helper function to convert fixed-width float string to float on device
// Assumes format like " 12.3" or "123.4" (5 chars)
__device__ float parse_float(const char* str, int len) {
    float result = 0.0f;
    float fraction = 0.0f;
    float divisor = 1.0f;
    int i = 0;
    int sign = 1;
    int found_digit = 0;
    int decimal_found = 0;

    // Skip leading spaces
    while (i < len && str[i] == ' ') {
        i++;
    }

    // Handle sign
    if (i < len && (str[i] == '-' || str[i] == '+')) {
        if (str[i] == '-') sign = -1;
        i++;
    }

    // Integer part
    while (i < len) {
        char c = str[i];
        if (c >= '0' && c <= '9') {
            found_digit = 1;
            result = result * 10.0f + (c - '0');
        } else if (c == '.') {
            decimal_found = 1;
            i++;
            break;
        } else if (c == ' ') {
            if (found_digit) break; // End of number
            i++;
        } else {
            break;
        }
        i++;
    }

    // Fractional part
    if (decimal_found) {
        while (i < len) {
            char c = str[i];
            if (c >= '0' && c <= '9') {
                divisor *= 10.0f;
                fraction += (c - '0') / divisor;
            } else if (c == ' ') {
                break;
            } else {
                break;
            }
            i++;
        }
    }

    return sign * (result + fraction);
}

