    for (int i = 0; i < cols; i++)
            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; i < cols; i++)
            printf("%d ",dst_host[i]) ;

    printf("\n") ;

#endif

    delete [] data;
    delete [] wall;
    delete [] dst_host;
    delete [] src_host;

    cudaFree(src_dev);
    cudaFree(dst_dev);
    cudaFree(wall_row_dev);
}

