__global__ void compute_coefficients_kernel(
    float *J, float *dN, float *dS, float *dW, float *dE, float *c,
    int *iN, int *iS, int *jW, int *jE,
    int rows, int cols, float q0sqr)
{
    int i = blockIdx.y * blockDim.y + threadIdx.y;
    int j = blockIdx.x * blockDim.x + threadIdx.x;

    if (i >= rows || j >= cols) return;

    int k = i * cols + j;
    float Jc = J[k];

    dN[k] = J[iN[i] * cols + j] - Jc;
    dS[k] = J[iS[i] * cols + j] - Jc;
    dW[k] = J[i * cols + jW[j]] - Jc;
    dE[k] = J[i * cols + jE[j]] - Jc;

    float G2 = (dN[k]*dN[k] + dS[k]*dS[k] + dW[k]*dW[k] + dE[k]*dE[k]) / (Jc*Jc);
    float L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

    float num = (0.5f * G2) - ((1.0f/16.0f) * (L*L));
    float den = 1.0f + (0.25f * L);
    float qsqr = num / (den * den);

    den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
    float val = 1.0f / (1.0f + den);

    if (val < 0.0f) val = 0.0f;
    else if (val > 1.0f) val = 1.0f;

    c[k] = val;
}

__global__ void update_kernel(
    float *J, float *c, float *dN, float *dS, float *dW, float *dE,
    int *iS, int *jE,
    int rows, int cols, float lambda)
{
    int i = blockIdx.y * blockDim.y + threadIdx.y;
    int j = blockIdx.x * blockDim.x + threadIdx.x;

    if (i >= rows || j >= cols) return;

    int k = i * cols + j;

    float cN = c[k];
    float cS = c[iS[i] * cols + j];
    float cW = c[k];
    float cE = c[i * cols + jE[j]];

    float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

    J[k] = J[k] + 0.25f * lambda * D;
}

