__global__ void speedy_update_kernel(Point *p, long k1, long k2, int i, int dim) {
  for (long k = k1 + blockIdx.x * blockDim.x + threadIdx.x; k < k2; k += blockDim.x) {
    float distance = dist(p[i], p[k], dim);
    if (p[k].cost > distance * p[k].weight) {
