__global__ void pgain_count_centers_kernel(bool *is_center, int *center_table, long k1, long k2, int *count_ptr) {
  int count = 0;
  for (long i = k1 + blockIdx.x * blockDim.x + threadIdx.x; i < k2; i += blockDim.x) {
