__global__ void pgain_accumulate_kernel(int *work_mem, int pid, int stride, int nproc) {
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    int accum = 0;
    for (int p = 0; p < nproc; p++) {
      int tmp = work_mem[p*stride];
      work_mem[p*stride] = accum;
      accum += tmp;
    }
  }
