__global__ void pgain_adjust_centers_kernel(bool *is_center, int *center_table, int *work_mem, int pid, int stride, long k1, long k2) {
  for (long i = k1 + blockIdx.x * blockDim.x + threadIdx.x; i < k2; i += blockDim.x) {
    if (is_center[i]) {
      center_table[i] += work_mem[pid*stride];
    }
  }
}

__global__ void pgain_compute_switch_kernel(Point *p, Point px, bool *switch_membership, double *lower, int *center_table, 
                                            long k1, long k2, int dim, double *cost_of_opening_x_ptr) {
  double cost_of_opening_x = 0;
  for (long i = k1 + blockIdx.x * blockDim.x + threadIdx.x; i < k2; i += blockDim.x) {
    float x_cost = dist(p[i], px, dim) * p[i].weight;
    float current_cost = p[i].cost;
    if (x_cost < current_cost) {
      switch_membership[i] = 1;
      cost_of_opening_x += (x_cost - current_cost);
    } else {
      int assign = p[i].assign;
      lower[center_table[assign]] += current_cost - x_cost;
    }
  }
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    *cost_of_opening_x_ptr = cost_of_opening_x;
  }
}

__global__ void pgain_compute_gl_lower_kernel(bool *is_center, double *work_mem, double *gl_lower, int *center_table, 
                                              int stride, int nproc, double z, long k1, long k2, int *num_close_ptr, double *cost_adj_ptr) {
  int number_of_centers_to_close = 0;
  double cost_adj = 0;
  for (long i = k1 + blockIdx.x * blockDim.x + threadIdx.x; i < k2; i += blockDim.x) {
    if (is_center[i]) {
      double low = z;
      for (int p = 0; p < nproc; p++) {
        low += work_mem[center_table[i] + p*stride];
      }
      gl_lower[center_table[i]] = low;
      if (low > 0) {
        number_of_centers_to_close++;
        cost_adj -= low;
      }
    }
  }
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    *num_close_ptr = number_of_centers_to_close;
    *cost_adj_ptr = cost_adj;
  }
}

__global__ void pgain_aggregate_kernel(double *work_mem, int stride, int nproc, int K, double *gl_cost_ptr, int *gl_num_close_ptr) {
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    double gl_cost_of_opening_x = z;
    int gl_number_of_centers_to_close = 0;
    for (int p = 0; p < nproc; p++) {
      gl_number_of_centers_to_close += (int)work_mem[p*stride + K];
      gl_cost_of_opening_x += work_mem[p*stride+K+1];
    }
    *gl_cost_ptr = gl_cost_of_opening_x;
    *gl_num_close_ptr = gl_number_of_centers_to_close;
