    if (blocks > 0) pgain_accumulate_kernel<<<1, 1>>>(work_mem, pid, stride, nproc);
  }

  if (blocks > 0) pgain_adjust_centers_kernel<<<blocks, threads_per_block>>>(is_center, center_table, work_mem, pid, stride, k1, k2);

  memset(switch_membership + k1, 0, (k2-k1)*sizeof(bool));
  memset(work_mem+pid*stride, 0, stride*sizeof(double));
  if( pid == 0 ) memset(work_mem+nproc*stride,0,stride*sizeof(double));

#ifdef PROFILE
  double t1 = gettime();
  if( pid == 0 ) time_gain_init = time_gain_init + (t1-t0);
#endif

  double* lower = &work_mem[pid*stride];
  double* gl_lower = &work_mem[nproc*stride];

  Point px = points->p[x];
  double *d_cost_opening;
  cudaMalloc(&d_cost_opening, sizeof(double));
  if (blocks > 0) pgain_compute_switch_kernel<<<blocks, threads_per_block>>>(points->p, px, switch_membership, lower, center_table, k1, k2, points->dim, d_cost_opening);
  cudaMemcpy(&cost_of_opening_x, d_cost_opening, sizeof(double), cudaMemcpyDeviceToHost);
