  cudaMemcpy(&cost_adj, d_cost_adj, sizeof(double), cudaMemcpyDeviceToHost);
  cudaFree(d_num_close);
  cudaFree(d_cost_adj);

  cost_of_opening_x += cost_adj;

  work_mem[pid*stride + K] = number_of_centers_to_close;
  work_mem[pid*stride + K+1] = cost_of_opening_x;

  if( pid == 0 ) {
    double *d_gl_cost;
    int *d_gl_num;
    cudaMalloc(&d_gl_cost, sizeof(double));
    cudaMalloc(&d_gl_num, sizeof(int));
