    cudaMemcpy(&gl_cost_of_opening_x, d_gl_cost, sizeof(double), cudaMemcpyDeviceToHost);
    cudaMemcpy(&gl_number_of_centers_to_close, d_gl_num, sizeof(int), cudaMemcpyDeviceToHost);
    cudaFree(d_gl_cost);
    cudaFree(d_gl_num);
  }

  if (gl_cost_of_opening_x < 0) {
    if (blocks > 0) pgain_update_points_kernel<<<blocks, threads_per_block>>>(points->p, switch_membership, is_center, center_table, gl_lower, px, k1, k2, points->dim, true);

